INSERT INTO `news` VALUES (38, 'Kimi回应马斯克点赞AI论文：你的火箭造得不错', 'https://36kr.com/newsflashes/3726732528728713?f=rss', 'https://36kr.com/feed', '36氪获悉，月之暗面 Kimi官方账号今天发布微博，回应马斯克点赞其最新技术报告：“你的火箭造得也不错！”3月16日，月之暗面Kimi发布技术报告，对大模型十年没有根本性变化的核心结构残差连接进行重新设计，使每一层能够选择性地关注此前各层输出，而非统一求和。测试显示，48B模型训练效率提升1.25倍。论文发布后，马斯克发文称“令人印象深刻”。', ' ', ' ', ' ', ' ', '36氪获悉，月之暗面 Kimi官方账号今天发布微博，回应马斯克点赞其最新技术报告：“你的火箭造得也不错！”3月16日，月之暗面Kimi发布技术报告，对大模型十年没有根本性变化的核心结构残差连接进行重新设计，使每一层能够选择性地关注此前各层输出，而非统一求和。测试显示，48B模型训练效率提升1.25倍。论文发布后，马斯克发文称“令人印象深刻”。', '2026-03-17 07:48:22', '2026-03-17 17:25:20');
INSERT INTO `news` VALUES (39, '康迪科技：与HawkRobo Systems LLC成立合资公司 KH Robotics', 'https://36kr.com/newsflashes/3726730033461635?f=rss', 'https://36kr.com/feed', '36氪获悉，3月17日，康迪科技宣布，与HawkRobo Systems LLC共同成立合资公司 KH Robotics，康迪以70%持股比例实现控股，原海康威视北美核心管理团队成员张卫民（Oliver Zhang）出任CEO。KH Robotics将以物流园区作为首个重点落地场景，相关成熟产品预计将在2026年内正式进入美国市场并启动商业交付。', ' ', ' ', ' ', ' ', '36氪获悉，3月17日，康迪科技宣布，与HawkRobo Systems LLC共同成立合资公司 KH Robotics，康迪以70%持股比例实现控股，原海康威视北美核心管理团队成员张卫民（Oliver Zhang）出任CEO。KH Robotics将以物流园区作为首个重点落地场景，相关成熟产品预计将在2026年内正式进入美国市场并启动商业交付。', '2026-03-17 07:45:49', '2026-03-17 17:25:20');
